/// Issue a credit note to adjust an invoice's amount after the invoice is finalized.
/// Related guide: [Credit notes](https://docs.stripe.com/billing/invoices/credit-notes)
type CreditNote =
    {
        /// The integer amount in cents (or local equivalent) representing the total amount of the credit note, including tax.
        Amount: int
        /// This is the sum of all the shipping amounts.
        AmountShipping: int
        /// Time at which the object was created. Measured in seconds since the Unix epoch.
        Created: DateTime
        /// Three-letter [ISO currency code](https://www.iso.org/iso-4217-currency-codes.html), in lowercase. Must be a [supported currency](https://stripe.com/docs/currencies).
        Currency: IsoTypes.IsoCurrencyCode
        /// ID of the customer.
        Customer: CreditNoteCustomer'AnyOf
        /// ID of the account representing the customer.
        CustomerAccount: string option
        /// Customer balance transaction related to this credit note.
        CustomerBalanceTransaction: CreditNoteCustomerBalanceTransaction'AnyOf option
        /// The integer amount in cents (or local equivalent) representing the total amount of discount that was credited.
        DiscountAmount: int
        /// The aggregate amounts calculated per discount for all line items.
        DiscountAmounts: DiscountsResourceDiscountAmount list
        /// The date when this credit note is in effect. Same as `created` unless overwritten. When defined, this value replaces the system-generated 'Date of issue' printed on the credit note PDF.
        EffectiveAt: DateTime option
        /// Unique identifier for the object.
        Id: string
        /// ID of the invoice.
        Invoice: CreditNoteInvoice'AnyOf
        /// Line items that make up the credit note
        Lines: CreditNoteLines
        /// If the object exists in live mode, the value is `true`. If the object exists in test mode, the value is `false`.
        Livemode: bool
        /// Customer-facing text that appears on the credit note PDF.
        Memo: string option
        /// Set of [key-value pairs](https://docs.stripe.com/api/metadata) that you can attach to an object. This can be useful for storing additional information about the object in a structured format.
        Metadata: Map<string, string> option
        /// A unique number that identifies this particular credit note and appears on the PDF of the credit note and its associated invoice.
        Number: string
        /// Amount that was credited outside of Stripe.
        OutOfBandAmount: int option
        /// The link to download the PDF of the credit note.
        Pdf: string
        /// The amount of the credit note that was refunded to the customer, credited to the customer's balance, credited outside of Stripe, or any combination thereof.
        PostPaymentAmount: int
        /// The amount of the credit note by which the invoice's `amount_remaining` and `amount_due` were reduced.
        PrePaymentAmount: int
        /// The pretax credit amounts (ex: discount, credit grants, etc) for all line items.
        PretaxCreditAmounts: CreditNotesPretaxCreditAmount list
        /// Reason for issuing this credit note, one of `duplicate`, `fraudulent`, `order_change`, or `product_unsatisfactory`
        Reason: CreditNoteReason option
        /// Refunds related to this credit note.
        Refunds: CreditNoteRefund list
        /// The details of the cost of shipping, including the ShippingRate applied to the invoice.
        ShippingCost: InvoicesResourceShippingCost option
        /// Status of this credit note, one of `issued` or `void`. Learn more about [voiding credit notes](https://docs.stripe.com/billing/invoices/credit-notes#voiding).
        Status: CreditNoteStatus
        /// The integer amount in cents (or local equivalent) representing the amount of the credit note, excluding exclusive tax and invoice level discounts.
        Subtotal: int
        /// The integer amount in cents (or local equivalent) representing the amount of the credit note, excluding all tax and invoice level discounts.
        SubtotalExcludingTax: int option
        /// The integer amount in cents (or local equivalent) representing the total amount of the credit note, including tax and all discount.
        Total: int
        /// The integer amount in cents (or local equivalent) representing the total amount of the credit note, excluding tax, but including discounts.
        TotalExcludingTax: int option
        /// The aggregate tax information for all line items.
        TotalTaxes: BillingBillResourceInvoicingTaxesTax list option
        /// Type of this credit note, one of `pre_payment` or `post_payment`. A `pre_payment` credit note means it was issued when the invoice was open. A `post_payment` credit note means it was issued when the invoice was paid.
        Type: CreditNoteType
        /// The time that the credit note was voided.
        VoidedAt: DateTime option
    }

and CreditNoteCustomerBalanceTransaction'AnyOf =
    | String of string
    | CustomerBalanceTransaction of CustomerBalanceTransaction

/// Each customer has a [Balance](https://docs.stripe.com/api/customers/object#customer_object-balance) value,
/// which denotes a debit or credit that's automatically applied to their next invoice upon finalization.
/// You may modify the value directly by using the [update customer API](https://docs.stripe.com/api/customers/update),
/// or by creating a Customer Balance Transaction, which increments or decrements the customer's `balance` by the specified `amount`.
/// Related guide: [Customer balance](https://docs.stripe.com/billing/customer/balance)
and CustomerBalanceTransaction =
    {
        /// The amount of the transaction. A negative value is a credit for the customer's balance, and a positive value is a debit to the customer's `balance`.
        Amount: int
        /// The ID of the checkout session (if any) that created the transaction.
        CheckoutSession: CustomerBalanceTransactionCheckoutSession'AnyOf option
        /// Time at which the object was created. Measured in seconds since the Unix epoch.
        Created: DateTime
        /// The ID of the credit note (if any) related to the transaction.
        CreditNote: CustomerBalanceTransactionCreditNote'AnyOf option
        /// Three-letter [ISO currency code](https://www.iso.org/iso-4217-currency-codes.html), in lowercase. Must be a [supported currency](https://stripe.com/docs/currencies).
        Currency: IsoTypes.IsoCurrencyCode
        /// The ID of the customer the transaction belongs to.
        Customer: CustomerBalanceTransactionCustomer'AnyOf
        /// The ID of an Account representing a customer that the transaction belongs to.
        CustomerAccount: string option
        /// An arbitrary string attached to the object. Often useful for displaying to users.
        Description: string option
        /// The customer's `balance` after the transaction was applied. A negative value decreases the amount due on the customer's next invoice. A positive value increases the amount due on the customer's next invoice.
        EndingBalance: int
        /// Unique identifier for the object.
        Id: string
        /// The ID of the invoice (if any) related to the transaction.
        Invoice: CustomerBalanceTransactionInvoice'AnyOf option
        /// If the object exists in live mode, the value is `true`. If the object exists in test mode, the value is `false`.
        Livemode: bool
        /// Set of [key-value pairs](https://docs.stripe.com/api/metadata) that you can attach to an object. This can be useful for storing additional information about the object in a structured format.
        Metadata: Map<string, string> option
        /// Transaction type: `adjustment`, `applied_to_invoice`, `credit_note`, `initial`, `invoice_overpaid`, `invoice_too_large`, `invoice_too_small`, `unspent_receiver_credit`, `unapplied_from_invoice`, `checkout_session_subscription_payment`, or `checkout_session_subscription_payment_canceled`. See the [Customer Balance page](https://docs.stripe.com/billing/customer/balance#types) to learn more about transaction types.
        Type: CustomerBalanceTransactionType
    }

and CustomerBalanceTransactionCreditNote'AnyOf =
    | String of string
    | CreditNote of CreditNote

/// Occurs whenever a credit note is voided.
type CreditNoteVoided = { Object: CreditNote }

/// Occurs whenever a credit note is updated.
type CreditNoteUpdated = { Object: CreditNote }

/// Occurs whenever a credit note is created.
type CreditNoteCreated = { Object: CreditNote }

/// Occurs when a Checkout Session is expired.
type CheckoutSessionExpired = { Object: CheckoutSession }

/// Occurs when a Checkout Session has been successfully completed.
